class Solution {
public:
    int findPairs(vector<int>& nums, int k) {
        if (k < 0) return 0;
        unordered_set<int> visited;
        unordered_set<int> pairs;
        for (int num : nums) {
            if (visited.find(num - k) != visited.end()) {
                pairs.insert(min(num, num - k));
            }
            if (k > 0 && visited.find(num + k) != visited.end()) {
                pairs.insert(min(num, num + k));
            }
            visited.insert(num);
        }
        return pairs.size();
    }
};
